<?php
// modules/student/notifications.php
require_once '../../config/database.php';

if (!isLoggedIn() || !hasRole('student')) {
    redirect('index.php');
}

// Mark all as read if requested
if (isset($_GET['mark_all_read'])) {
    $conn->query("UPDATE notifications SET is_read = 1 WHERE user_id = {$_SESSION['user_id']}");
    redirect('notifications.php');
}

// Mark single as read
if (isset($_GET['read'])) {
    $id = (int)$_GET['read'];
    $conn->query("UPDATE notifications SET is_read = 1 WHERE id = $id AND user_id = {$_SESSION['user_id']}");
    redirect('notifications.php');
}

$notifications = $conn->query("SELECT * FROM notifications WHERE user_id = {$_SESSION['user_id']} ORDER BY created_at DESC");
$unread_count = getUnreadNotificationsCount($_SESSION['user_id']);
?>
